-- ── Memory domains ────────────────────────────────────────────────────────────
local WRAM    = "WRAM"
local CARTROM = "CARTROM"     -- SNES cartridge ROM in BizHawk; fallbacks below

-- ── Addresses / constants (worlds/dkc/Client.py module top) ───────────────────
-- Expressed as BizHawk-domain offsets (already net of WRAM_START / ROM_START).
local STAGE_FLAGS_OFF   = 0x0583      -- WRAM: base of the 0x100-byte level-flag array
local SANITY_FLAGS_OFF  = 0x1F800     -- WRAM: base of the 0x100-byte sanity-flag array
local NMI_POINTER_OFF   = 0x001C      -- WRAM: u16 LE; == 0xE6B1 while in a map
local CURRENT_LEVEL_OFF = 0x0563      -- WRAM: id of the level currently being played
local LOADED_LEVEL_OFF  = 0x003E      -- WRAM: loaded level id (goal: == 0x4C)
local BRIGHTNESS_OFF    = 0x051A      -- WRAM: screen brightness; & 0x0F == 0x0F = full
local KONG_LETTERS_OFF  = 0x057F      -- WRAM: KONG-letter flags; & 0x10 == complete
local ROMHASH_OFF       = 0xFFC0      -- CARTROM: ROM-header title; first 4 = "DKC1"

-- Sentinel values.
local IN_MAP_NMI        = 0xE6B1      -- nmi_pointer value while on the world map
local GOAL_LOADED_LEVEL = 0x004C      -- loaded_level value on the K. Rool ending map
local REPTILE_RUMBLE_ALT= 0xEA        -- current_level alias remapped to 0x01

